#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int maxCount = 0;
        int maxIndex = -1;
        for (int i = 0; i < n; ++i) {
            int cnt = 0;
            for (int j = 0; j < m; ++j) {
                int x;
                scanf("%d", &x);
                if (x == 1) ++cnt;
            }
            if (cnt > maxCount) {
                maxCount = cnt;
                maxIndex = i;
            }
        }
        printf("%d\n", maxIndex);
    }
    return 0;
}

