import sys

def main():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it))
        m = int(next(it))
        max_cnt = 0
        max_idx = -1
        for i in range(n):
            cnt = 0
            for _ in range(m):
                if int(next(it)) == 1:
                    cnt += 1
            if cnt > max_cnt:
                max_cnt = cnt
                max_idx = i
        out_lines.append(str(max_idx))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

